-- Repopula enem_resultados com TODAS as escolas do PR (ENEM 2024 e 2025).
-- Fonte: ENEM_Todas_Escolas_Parana_2024.xlsx / _2025.xlsx (todas as dependencias, inclui privadas).
-- Novo: coluna parceiro ('apg'|'salta'|'tom') marcada por codigo INEP; is_apogeu = (parceiro='apg').
--       coluna participantes = 'Participantes ENEM'; alunos = 'Alunos (validos p/ media)'.

ALTER TABLE enem_resultados ADD COLUMN IF NOT EXISTS parceiro text;
ALTER TABLE enem_resultados ADD COLUMN IF NOT EXISTS participantes integer;
ALTER TABLE enem_resultados DROP CONSTRAINT IF EXISTS enem_parceiro_check;
ALTER TABLE enem_resultados ADD CONSTRAINT enem_parceiro_check CHECK (parceiro IN ('apg','salta','tom'));
CREATE INDEX IF NOT EXISTS idx_enem_parceiro ON enem_resultados (parceiro);

DELETE FROM enem_resultados;











